import{_ as e,c as a,o as t,a as r}from"./app.015fbf38.js";const m='{"title":"\u5361\u8E0F","description":"","frontmatter":{},"headers":[],"relativePath":"Bike/BikeInfo/\u5361\u8E0F.md","lastUpdated":1648513476161}',o={},_=r('<h1 id="\u5361\u8E0F" tabindex="-1">\u5361\u8E0F <a class="header-anchor" href="#\u5361\u8E0F" aria-hidden="true">#</a></h1><h6 id="tags-\u516C\u8DEF\u8ECA" tabindex="-1">tags: <code>\u516C\u8DEF\u8ECA</code> <a class="header-anchor" href="#tags-\u516C\u8DEF\u8ECA" aria-hidden="true">#</a></h6><p><a href="https://m.mobile01.com/topicdetail.php?f=318&amp;t=4978612&amp;p=2" target="_blank" rel="noopener noreferrer">Reference</a></p><p>\u8F2A\u7D44\u662F\u76F4\u63A5\u7684\u63D0\u5347\u4F60\u7684\u901F\u5EA6, \u5361\u8E0F\u662F\u9593\u63A5\u7684\u63D0\u5347(\u6539\u5584\u4F60\u8E29\u7684\u59FF\u52E2/\u6548\u7387, \u8B93\u4F60\u51FA\u7684\u529B\u66F4\u6709\u6548\u7387), \u5169\u8005\u76EE\u7684\u7D42\u6B78\u90FD\u662F\u4E00\u6A23, \u8B93\u4F60\u8F15\u9B06\u9EDE \u7BC0\u7701\u9AD4\u529B, \u597D\u9A0E\u5F97\u66F4\u5FEB\u66F4\u9060. \u6A13\u4E0Awhatar\u5927\u9019\u4E00\u53E5\u8AAA\u5F97\u5F88\u68D2, &quot;\u4E0A\u4E86\u5361\u624D\u53EF\u4EE5\u628A\u5668\u6750\u7684\u5BE6\u529B\u767C\u63EE\u51FA\u4F86&quot;. \u4E0D\u904E\u4E0A\u4E0D\u4E0A\u5361\u662F\u53D6\u6C7A\u65BC\u4F60\u5C0D\u9019\u9805\u904B\u52D5\u6295\u5165\u7684\u7A0B\u5EA6, \u5176\u5BE6\u53EA\u662F\u975E\u5E38\u7C21\u55AE\u7684\u6771\u897F, \u4E0D\u904E\u5F88\u591A\u4EBA\u4F11\u9592\u9A0E\u5C31\u6EFF\u8DB3\u4E86, \u6709\u9019\u7A2E\u5FC3\u614B\u5BB9\u6613\u6454\u7576\u7136\u4E5F\u5C31\u4E0D\u5947\u602A\u4E86. \u5982\u679C\u5FC3\u614B\u662F\u4E0D\u4E00\u6A23\u7684, \u7D50\u679C\u5C31\u662F\u4E0D\u4E00\u6A23\u7684.</p><p>\u5CF6\u91CESPD-SL\u7684\u6263\u7247, \u6211\u60F3\u5B83\u8A2D\u8A08\u7684\u76EE\u7684\u5C31\u53EA\u662F\u8981\u8B93\u6211\u5011\u9A0E, \u5E38\u62FF\u4F86\u8D70\u4F86\u8D70\u53BB\u78E8\u640D\u81EA\u7136\u5FEB. \u6211\u6709\u5169\u96D9R170, \u5728R170\u505C\u7522/R171\u4E0A\u5E02\u524D\u5169\u500B\u6708\u8CB7\u7684, \u7576\u6642\u88DD\u4E0A\u7684\u6263\u7247\u7528\u5230\u73FE\u5728\u9084\u5728\u7528, \u78E8\u640D\u7A0B\u5EA6\u5927\u6982\u4E0D\u523050%, \u5169\u96D9\u61C9\u90FD\u7528\u4E86\u8D85\u904E\u4E00\u842C\u4E8C\u5343km. \u73FE\u5728R171\u90FD\u505C\u7522\u4E86, \u600E\u9EBC\u6703\u7528\u9019\u9EBC\u4E45\u5462? \u56E0\u70BA\u6211\u53EA\u6709\u727D\u8ECA\u51FA/\u5165\u6642\u6709\u7528\u5B83\u4F86\u8D70\u8DEF\u800C\u5DF2. \u6211\u5C6F\u7684\u53E6\u59165\u500B\u6263\u7247\u90FD\u9084\u6C92\u6709\u6A5F\u6703\u63DB\u4E0A. \u5982\u679C\u6211\u518D\u8CB7\u5169\u96D9\u5361\u978B\u4F86\u4E92\u63DB, \u5927\u6982\u8981......\u5F88\u4E45\u5F88\u4E45\u4EE5\u5F8C\u624D\u9700\u8981\u63DB\u6263\u7247</p>',5),n=[_];function s(c,d,i,p,h,l){return t(),a("div",null,n)}var u=e(o,[["render",s]]);export{m as __pageData,u as default};
